/*!50003 DROP PROCEDURE IF EXISTS `amortizacion_des_cuotas` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `amortizacion_des_cuotas`(
    IN p_id_prestamo BIGINT,
    IN p_numero_cuota_inicio INT
)
BEGIN
    DECLARE v_prestamo INT;

    SELECT COUNT(*)
    INTO v_prestamo
    FROM prestamo
    WHERE id_prestamo = p_id_prestamo;

    IF v_prestamo = 0 THEN

        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT =
        'Prestamo no existe';

    END IF;

    UPDATE prestamo_amortizacion
    SET estado = 'REMPLAZADA'
    WHERE
        id_prestamo = p_id_prestamo
        AND numero_cuota >= p_numero_cuota_inicio
        AND estado IN (
            'PENDIENTE',
            'PARCIAL',
            'VENCIDA'
        );

END ;;
DELIMITER ;
