/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `registrar_cuota_prestamo`(id_prestamo_ int,
monto_total_ DECIMAL(18,2),referencia_ text,
observacion_ text,id_cuenta_financiera_ int)
BEGIN
 -- ============================================
    -- VARIABLES
    -- ============================================

    DECLARE cuota_ DECIMAL(18,2) DEFAULT 0;
    DECLARE capital_ DECIMAL(18,2) DEFAULT 0;
    DECLARE interes_ DECIMAL(18,2) DEFAULT 0;
    DECLARE mora_ DECIMAL(18,2) DEFAULT 0;

    DECLARE id_pago_ BIGINT;
    DECLARE id_amortizacion_ BIGINT;
	DECLARE id_tipo_movimiento_ text DEFAULT 35;

    -- ============================================
    -- HANDLER DE ERRORES
    -- ============================================

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN

        ROLLBACK;

        SELECT
            'ERROR AL REGISTRAR PAGO' AS mensaje;

    END;

    -- ============================================
    -- VALIDAR MONTO
    -- ============================================

    IF monto_total_ <= 0 THEN

        SELECT
            'EL MONTO DEBE SER MAYOR A 0' AS mensaje;
        ELSE

        -- ========================================
        -- INICIAR TRANSACCIÓN
        -- ========================================

        START TRANSACTION;

        -- ========================================
        -- OBTENER PRÓXIMA CUOTA
        -- ========================================

        SELECT 
            IFNULL(cuota_total,0),
            id_amortizacion,
            IFNULL(capital,0),
            IFNULL(interes,0),
            IFNULL(mora,0)

        INTO 
            cuota_,
            id_amortizacion_,
            capital_,
            interes_,
            mora_

        FROM prestamo_amortizacion

        WHERE id_prestamo = id_prestamo_

        AND estado IN ('PENDIENTE', 'PARCIAL', 'VENCIDA')

        ORDER BY fecha_pago ASC

        LIMIT 1

        FOR UPDATE;


			IF (capital_ + interes_ + mora_) <> cuota_ THEN

				SIGNAL SQLSTATE '45000'
				SET MESSAGE_TEXT = 'INCONSISTENCIA EN AMORTIZACION';

			END IF;
        -- ========================================
        -- VALIDAR EXISTENCIA DE CUOTA
        -- ========================================
        
        

        IF id_amortizacion_ IS NOT NULL THEN

            -- ====================================
            -- VALIDAR MONTO
            -- ====================================

            IF monto_total_ >= (cuota_ + mora_) THEN

                -- ================================
                -- REGISTRAR PAGO
                -- ================================

                INSERT INTO prestamo_pago
                (
                    id_prestamo,
                    fecha_pago,
                    monto_total,
                    referencia,
                    observacion
                )
                VALUES
                (
                    id_prestamo_,
                    NOW(),
                    monto_total_,
                    referencia_,
                    observacion_
                );

                -- ================================
                -- OBTENER ID PAGO
                -- ================================

                SET id_pago_ = LAST_INSERT_ID();

                -- ================================
                -- DETALLE DEL PAGO
                -- ================================

                INSERT INTO prestamo_pago_detalle
                (
                    id_pago,
                    tipo_aplicacion,
                    monto
                )
                VALUES
                    (id_pago_, 'MORA', mora_),
                    (id_pago_, 'INTERES', interes_),
                    (id_pago_, 'CAPITAL', capital_);

                -- ================================
                -- ACTUALIZAR CUOTA
                -- ================================

                UPDATE prestamo_amortizacion
                SET estado = 'PAGADA'
                WHERE id_amortizacion = id_amortizacion_;
                
                -- Aqui inserto el movimiento
                
                SELECT id_tipo_movimiento into id_tipo_movimiento_ FROM cooperativa_db.tipo_movimiento_financiero 
                WHERE codigo = "PAGO_CUOTA_PRESTAMO";
                
                INSERT INTO `cooperativa_db`.`movimiento_financiero`
                (`id_cuenta_financiera`, `id_tipo_movimiento`, `fecha_movimiento`,
                `monto`,`monto_cuota_prestamo`, `saldo_anterior`, `saldo_nuevo`, `descripcion`)
                VALUES (id_cuenta_financiera_, id_tipo_movimiento_, now(), capital_,cuota_, '0', '12', 'Pago cuota');


                -- ================================
                -- CONFIRMAR
                -- ================================

                COMMIT;

                SELECT
                    'PAGO REGISTRADO CORRECTAMENTE' AS mensaje,
                    id_pago_ AS id_pago;

            ELSE

                ROLLBACK;

                SELECT
                    'CUOTA NO VALIDA' AS mensaje;

            END IF;

        ELSE

            ROLLBACK;

            SELECT
                'NO EXISTEN CUOTAS PENDIENTES' AS mensaje;

        END IF;

    END IF;
END ;;
DELIMITER ;
